1	const PROCESSING_FEE = 5;
2	const DEFAULT_BASE_PREMIUM = 100;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_THRESHOLD_YEARS = 2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	const DEFAULT_INSURANCE_VALUE = 1000;
13	
14	type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
15	type Damage = { itemType: string; amount: number };
16	type Incident = { cause: string; damages: Damage[] };
17	type Step =
18	  | { op: "quote"; items: QuoteItem[] }
19	  | { op: "claim"; policy: number; incident: Incident };
20	type Customer = { yearsWithMHPCO: number };
21	type Scenario = { customer: Customer; steps: Step[] };
22	
23	const BLOCK_TYPE = "block";
24	const BLOCK_OF_THREE_BASE = 60;
25	const BLOCK_SIZE = 3;
26	
27	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
28	  amulet: 60,
29	  rune: 25,
30	  moonstone: 25,
31	  [BLOCK_TYPE]: BLOCK_OF_THREE_BASE,
32	};
33	const BLOCK_TYPES = new Set(["rune", "moonstone"]);
34	
35	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
36	  sword: 1000,
37	  amulet: 600,
38	  staff: 800,
39	  potion: 400,
40	  rune: 250,
41	  moonstone: 250,
42	};
43	
44	const insuranceValueForItem = (item: QuoteItem): number =>
45	  INSURANCE_VALUE_BY_TYPE[item.type] ?? DEFAULT_INSURANCE_VALUE;
46	
47	const basePremiumForItem = (item: QuoteItem): number =>
48	  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
49	
50	const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
51	  items.reduce((groups, item) => {
52	    const group = groups.get(item.type) ?? [];
53	    return groups.set(item.type, [...group, item]);
54	  }, new Map<string, QuoteItem[]>());
55	
56	const isHighEnchantment = (item: QuoteItem): boolean =>
57	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
58	
59	const itemSurchargeRate = (item: QuoteItem): number =>
60	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
61	  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
62	  FIRST_INSURANCE_RATE;
63	
64	const itemPremium = (item: QuoteItem): number => {
65	  const base = basePremiumForItem(item);
66	  return base + base * itemSurchargeRate(item);
67	};
68	
69	const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
70	  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;
71	
72	const billingItems = (items: QuoteItem[]): QuoteItem[] =>
73	  [...groupByType(items)].flatMap(([type, group]) =>
74	    isBlockGroup(type, group) ? [{ type: BLOCK_TYPE }] : group,
75	  );
76	
77	const sumBy = <T>(items: T[], fn: (item: T) => number): number =>
78	  items.reduce((total, item) => total + fn(item), 0);
79	
80	const policyDiscountRate = (customer: Customer, quoteIndex: number): number =>
81	  (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0) +
82	  (quoteIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0);
83	
84	type QuoteResult = { premium: number };
85	type ClaimResult = { payout: number; remainingCap: number };
86	type StepResult = QuoteResult | ClaimResult;
87	
88	type Policy = { items: QuoteItem[]; remainingCap: number };
89	
90	const quoteStep = (
91	  customer: Customer,
92	  quoteIndex: number,
93	  items: QuoteItem[],
94	): QuoteResult => {
95	  const billables = billingItems(items);
96	  const policyBase = sumBy(billables, basePremiumForItem);
97	  const subtotal = sumBy(billables, itemPremium);
98	  const discount = policyBase * policyDiscountRate(customer, quoteIndex);
99	  return { premium: Math.ceil(subtotal - discount + PROCESSING_FEE) };
100	};
101	
102	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
103	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
104	const FULL_PAYOUT_RATE = 1;
105	
106	const payoutRate = (item: QuoteItem | undefined): number =>
107	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
108	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
109	    : FULL_PAYOUT_RATE;
110	
111	const findInsuredItem = (policy: Policy, itemType: string): QuoteItem | undefined =>
112	  policy.items.find((it) => it.type === itemType);
113	
114	const damagePayout = (policy: Policy, dmg: Damage): number =>
115	  dmg.amount * payoutRate(findInsuredItem(policy, dmg.itemType)) - DEDUCTIBLE;
116	
117	const claimStep = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
118	  const payout = sumBy(incident.damages, (dmg) => damagePayout(policy, dmg));
119	  const remainingCap = policy.remainingCap - payout;
120	  return {
121	    result: { payout, remainingCap },
122	    policy: { ...policy, remainingCap },
123	  };
124	};
125	
126	const policyFromItems = (items: QuoteItem[]): Policy => ({
127	  items,
128	  remainingCap: sumBy(items, insuranceValueForItem) * CAP_MULTIPLIER,
129	});
130	
131	type ScenarioState = {
132	  results: StepResult[];
133	  quoteIndex: number;
134	  policies: Record<number, Policy>;
135	};
136	
137	const initialState: ScenarioState = { results: [], quoteIndex: 0, policies: {} };
138	
139	const applyStep = (
140	  customer: Customer,
141	  state: ScenarioState,
142	  step: Step,
143	  index: number,
144	): ScenarioState => {
145	  if (step.op === "quote") {
146	    const result = quoteStep(customer, state.quoteIndex, step.items);
147	    return {
148	      results: [...state.results, result],
149	      quoteIndex: state.quoteIndex + 1,
150	      policies: { ...state.policies, [index]: policyFromItems(step.items) },
151	    };
152	  }
153	  const { result, policy } = claimStep(state.policies[step.policy], step.incident);
154	  return {
155	    results: [...state.results, result],
156	    quoteIndex: state.quoteIndex,
157	    policies: { ...state.policies, [step.policy]: policy },
158	  };
159	};
160	
161	export const runScenario = (scenario: unknown): unknown => {
162	  const { customer, steps } = scenario as Scenario;
163	  const { results } = steps.reduce(
164	    (state, step, index) => applyStep(customer, state, step, index),
165	    initialState,
166	  );
167	  return { results };
168	};
